import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { Account, Contact, Opportunity, STAGE_META } from '../../models/models';

@Component({
  selector: 'app-account-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './account-detail.component.html',
  styleUrl: './accounts.css',
})
export class AccountDetailComponent {
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  private pm = toSignal(this.route.paramMap, { initialValue: this.route.snapshot.paramMap });
  private qm = toSignal(this.route.queryParamMap, { initialValue: this.route.snapshot.queryParamMap });
  readonly id = computed(() => this.pm().get('id') ?? '');
  readonly showDelete = computed(() => this.qm().get('modal') === 'delete');

  accounts = signal<Account[]>([
    { id: 'a1', name: 'Acme Corporation', industry: 'Manufacturing', website: 'acme.com', phone: '+1 415 555 0100', city: 'San Francisco', employees: 4200, annualRevenue: 320000000, owner: 'Demo Admin' },
    { id: 'a2', name: 'Globex Industries', industry: 'Technology', website: 'globex.io', phone: '+1 212 555 0142', city: 'New York', employees: 1800, annualRevenue: 145000000, owner: 'Priya Nair' },
    { id: 'a3', name: 'Initech', industry: 'Finance', website: 'initech.com', phone: '+1 512 555 0188', city: 'Austin', employees: 640, annualRevenue: 58000000, owner: 'Marco Diaz' },
    { id: 'a4', name: 'Umbrella Health', industry: 'Healthcare', website: 'umbrella-health.org', phone: '+1 617 555 0164', city: 'Boston', employees: 9500, annualRevenue: 1200000000, owner: 'Demo Admin' },
  ]);

  contacts = signal<Contact[]>([
    { id: 'c1', firstName: 'Jane', lastName: 'Rivera', title: 'VP Operations', email: 'jane@acme.com', phone: '+1 415 555 0110', accountId: 'a1', accountName: 'Acme Corporation', owner: 'Demo Admin' },
    { id: 'c2', firstName: 'Sam', lastName: 'Okafor', title: 'CTO', email: 'sam@acme.com', phone: '+1 415 555 0111', accountId: 'a1', accountName: 'Acme Corporation', owner: 'Priya Nair' },
    { id: 'c3', firstName: 'Lena', lastName: 'Park', title: 'Procurement Lead', email: 'lena@globex.io', phone: '+1 212 555 0150', accountId: 'a2', accountName: 'Globex Industries', owner: 'Marco Diaz' },
  ]);

  opportunities = signal<Opportunity[]>([
    { id: 'o1', name: 'Acme — Platform Renewal', accountId: 'a1', accountName: 'Acme Corporation', stage: 'NEGOTIATION', amount: 120000, closeDate: '2026-08-15', probability: 75, owner: 'Demo Admin' },
    { id: 'o6', name: 'Acme Field Service Add-on', accountId: 'a1', accountName: 'Acme Corporation', stage: 'PROPOSAL', amount: 38000, closeDate: '2026-09-20', probability: 55, owner: 'Priya Nair' },
    { id: 'o2', name: 'Globex Data Migration', accountId: 'a2', accountName: 'Globex Industries', stage: 'PROPOSAL', amount: 84000, closeDate: '2026-07-30', probability: 60, owner: 'Priya Nair' },
  ]);

  readonly account = computed(() => this.accounts().find((a) => a.id === this.id()) ?? this.accounts()[0]);
  readonly relatedContacts = computed(() => this.contacts().filter((c) => c.accountId === this.account().id));
  readonly relatedOpps = computed(() => this.opportunities().filter((o) => o.accountId === this.account().id));

  stageLabel(key: string): string {
    return STAGE_META.find((s) => s.key === key)?.label ?? key;
  }

  askDelete(): void {
    this.router.navigate([], { queryParams: { modal: 'delete' }, queryParamsHandling: 'merge' });
  }
  cancelDelete(): void {
    this.router.navigate([], { queryParams: { modal: null }, queryParamsHandling: 'merge' });
  }
  confirmDelete(): void {
    this.accounts.update((list) => list.filter((a) => a.id !== this.account().id));
    this.router.navigate(['/accounts']);
  }
}
